    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<Owner>().HasMany(o => o.Pets).WithOne(p => p.Owner).HasForeignKey(p => p.OwnerId);
        builder.Entity<Pet>().HasMany(p => p.Treatments).WithOne(t => t.Pet).HasForeignKey(t => t.PetId);
        builder.Entity<Pet>().HasMany(p => p.Appointments).WithOne(a => a.Pet).HasForeignKey(a => a.PetId);
        builder.Entity<Invoice>().HasMany(i => i.Items).WithOne(item => item.Invoice).HasForeignKey(item => item.InvoiceId);
        builder.Entity<Invoice>().HasMany(i => i.Payments).WithOne(p => p.Invoice).HasForeignKey(p => p.InvoiceId);
    }
}

