@page "/patients"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Patients</PageTitle>

<h1>🐕 Patient Records</h1>

<div class="row mt-3">
    <div class="col-md-5">
        <div class="card">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>@(editingOwner == null ? "Register New Owner & Pet" : "Edit Owner")</strong>
                @if (editingOwner != null)
                {
                    <button class="btn btn-sm btn-outline-secondary" @onclick="ResetForm">Cancel</button>
                }
            </div>
            <div class="card-body">
                <EditForm Model="ownerForm" OnValidSubmit="SaveOwner" FormName="ownerForm">
                    <DataAnnotationsValidator />
                    <div class="mb-2">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="ownerForm.FirstName" />
                        <ValidationMessage For="() => ownerForm.FirstName" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="ownerForm.LastName" />
                        <ValidationMessage For="() => ownerForm.LastName" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="ownerForm.Phone" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="ownerForm.Email" />
                    </div>
                    <button type="submit" class="btn btn-success">@(editingOwner == null ? "Register Owner" : "Update Owner")</button>
                </EditForm>

                @if (editingOwner == null)
                {
                    <hr />
                    <h6>Add Pet</h6>
                    <EditForm Model="petForm" OnValidSubmit="SavePet" FormName="petForm">
                        <DataAnnotationsValidator />
                        <div class="mb-2">
                            <label class="form-label">Owner</label>
                            <InputSelect class="form-select" @bind-Value="petForm.OwnerId">
                                <option value="0">-- Select Owner --</option>
                                @foreach (var o in owners)
                                {
                                    <option value="@o.Id">@o.FullName</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Pet Name</label>
                            <InputText class="form-control" @bind-Value="petForm.Name" />
                            <ValidationMessage For="() => petForm.Name" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Species</label>
                            <InputSelect class="form-select" @bind-Value="petForm.Species">
                                <option value="">-- Select --</option>
                                <option>Dog</option>
                                <option>Cat</option>
                                <option>Bird</option>
                                <option>Rabbit</option>
                                <option>Reptile</option>
                                <option>Other</option>
                            </InputSelect>
                            <ValidationMessage For="() => petForm.Species" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Breed</label>
                            <InputText class="form-control" @bind-Value="petForm.Breed" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Weight (kg)</label>
                            <InputNumber class="form-control" @bind-Value="petForm.WeightKg" />
                        </div>
                        <button type="submit" class="btn btn-primary">Register Pet</button>
                    </EditForm>
                }
            </div>
        </div>
    </div>

    <div class="col-md-7">
        <div class="mb-3">
            <input type="text" class="form-control" placeholder="Search pets or owners..." @bind="searchTerm" @bind:event="oninput" />
        </div>

        @foreach (var owner in FilteredOwners)
        {
            <div class="card mb-2">
                <div class="card-header d-flex justify-content-between">
                    <span><strong>@owner.FullName</strong> — @owner.Phone</span>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => EditOwner(owner)">Edit</button>
                </div>
                <div class="card-body p-2">
                    @foreach (var pet in owner.Pets)
                    {
                        <div class="border rounded p-2 mb-2">
                            <div class="d-flex justify-content-between">
                                <span><strong>@pet.Name</strong> (@pet.Species@(pet.Breed != null ? $" - {pet.Breed}" : "")) @(pet.WeightKg.HasValue ? $"{pet.WeightKg} kg" : "")</span>
                                <button class="btn btn-sm btn-outline-info" @onclick="() => SelectPet(pet)">Medical History</button>
                            </div>
                        </div>
                    }
                </div>
            </div>
        }
    </div>
</div>

@if (selectedPet != null)
{
    <div class="modal fade show d-block" tabindex="-1" style="background:rgba(0,0,0,0.5)">
        <div class="modal-dialog modal-lg">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Medical History — @selectedPet.Name</h5>
                    <button type="button" class="btn-close" @onclick="() => selectedPet = null"></button>
                </div>
                <div class="modal-body">
                    <h6>Add Treatment Note</h6>
                    <EditForm Model="treatmentForm" OnValidSubmit="SaveTreatment" FormName="treatmentForm">
                        <DataAnnotationsValidator />
                        <div class="row mb-2">
                            <div class="col">
                                <InputText class="form-control" placeholder="Description" @bind-Value="treatmentForm.Description" />
                                <ValidationMessage For="() => treatmentForm.Description" />
                            </div>
                            <div class="col-auto">
                                <InputNumber class="form-control" placeholder="Cost" @bind-Value="treatmentForm.Cost" />
                            </div>
                        </div>
                        <div class="mb-2">
                            <InputTextArea class="form-control" placeholder="Notes..." @bind-Value="treatmentForm.Notes" />
                        </div>
                        <div class="row mb-2">
                            <div class="col">
                                <InputText class="form-control" placeholder="Performed by" @bind-Value="treatmentForm.PerformedBy" />
                            </div>
                            <div class="col-auto">
                                <button type="submit" class="btn btn-success">Add Treatment</button>
                            </div>
                        </div>
                    </EditForm>
                    <hr />
                    <table class="table table-sm">
                        <thead>
                            <tr><th>Date</th><th>Description</th><th>Notes</th><th>By</th><th>Cost</th></tr>
                        </thead>
                        <tbody>
                            @foreach (var t in selectedPet.Treatments.OrderByDescending(t => t.Date))
                            {
                                <tr>
                                    <td>@t.Date.ToShortDateString()</td>
                                    <td>@t.Description</td>
                                    <td>@t.Notes</td>
                                    <td>@t.PerformedBy</td>
                                    <td>@t.Cost.ToString("C")</td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private List<Owner> owners = new();
    private string searchTerm = "";
    private Owner? editingOwner;
    private Pet? selectedPet;

    private OwnerFormModel ownerForm = new();
    private PetFormModel petForm = new();
    private TreatmentFormModel treatmentForm = new();

    private IEnumerable<Owner> FilteredOwners => string.IsNullOrWhiteSpace(searchTerm)
        ? owners
        : owners.Where(o =>
            o.FullName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            o.Pets.Any(p => p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)));

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        owners = await db.Owners.Include(o => o.Pets).ThenInclude(p => p.Treatments).ToListAsync();
    }

    private async Task SaveOwner()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        if (editingOwner != null)
        {
            var owner = await db.Owners.FindAsync(editingOwner.Id);
            if (owner != null)
            {
                owner.FirstName = ownerForm.FirstName;
                owner.LastName = ownerForm.LastName;
                owner.Phone = ownerForm.Phone;
                owner.Email = ownerForm.Email;
                await db.SaveChangesAsync();
            }
            editingOwner = null;
        }
        else
        {
            var owner = new Owner
            {
                FirstName = ownerForm.FirstName,
                LastName = ownerForm.LastName,
                Phone = ownerForm.Phone,
                Email = ownerForm.Email
            };
            db.Owners.Add(owner);
            await db.SaveChangesAsync();
        }
        ownerForm = new();
        await LoadData();
    }

    private async Task SavePet()
    {
        if (petForm.OwnerId == 0) return;
        using var db = await DbFactory.CreateDbContextAsync();
        var pet = new Pet
        {
            Name = petForm.Name,
            Species = petForm.Species,
            Breed = petForm.Breed,
            WeightKg = petForm.WeightKg,
            OwnerId = petForm.OwnerId
        };
        db.Pets.Add(pet);
        await db.SaveChangesAsync();
        petForm = new();
        await LoadData();
    }

    private void EditOwner(Owner owner)
    {
        editingOwner = owner;
        ownerForm = new OwnerFormModel
        {
            FirstName = owner.FirstName,
            LastName = owner.LastName,
            Phone = owner.Phone,
            Email = owner.Email
        };
    }

    private void ResetForm()
    {
        editingOwner = null;
        ownerForm = new();
    }

    private void SelectPet(Pet pet)
    {
        selectedPet = pet;
        treatmentForm = new();
    }

    private async Task SaveTreatment()
    {
        if (selectedPet == null) return;
        using var db = await DbFactory.CreateDbContextAsync();
        var treatment = new Treatment
        {
            PetId = selectedPet.Id,
            Date = DateTime.Now,
            Description = treatmentForm.Description,
            Notes = treatmentForm.Notes,
            PerformedBy = treatmentForm.PerformedBy,
            Cost = treatmentForm.Cost
        };
        db.Treatments.Add(treatment);
        await db.SaveChangesAsync();
        treatmentForm = new();
        await LoadData();
        selectedPet = owners.SelectMany(o => o.Pets).FirstOrDefault(p => p.Id == selectedPet.Id);
    }

    private class OwnerFormModel
    {
        [Required] public string FirstName { get; set; } = "";
        [Required] public string LastName { get; set; } = "";
        public string? Phone { get; set; }
        public string? Email { get; set; }
    }

    private class PetFormModel
    {
        public int OwnerId { get; set; }
        [Required] public string Name { get; set; } = "";
        [Required] public string Species { get; set; } = "";
        public string? Breed { get; set; }
        public double? WeightKg { get; set; }
    }

    private class TreatmentFormModel
    {
        [Required] public string Description { get; set; } = "";
        public string? Notes { get; set; }
        public string? PerformedBy { get; set; }
        public decimal Cost { get; set; }
    }
}

@page "/appointments"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Appointments</PageTitle>

<h1>📅 Appointment Scheduling</h1>

<div class="row mt-3">
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">
                <strong>@(editingAppointment == null ? "New Appointment" : "Edit Appointment")</strong>
            </div>
            <div class="card-body">
                <EditForm Model="form" OnValidSubmit="SaveAppointment" FormName="appointmentForm">
                    <DataAnnotationsValidator />
                    <div class="mb-2">
                        <label class="form-label">Pet</label>
                        <InputSelect class="form-select" @bind-Value="form.PetId">
                            <option value="0">-- Select Pet --</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Date</label>
                        <InputDate class="form-control" @bind-Value="form.Date" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Start Time</label>
                        <InputSelect class="form-select" @bind-Value="form.StartHour">
                            @foreach (var hour in Enumerable.Range(8, 10))
                            {
                                <option value="@hour">@($"{hour:D2}:00")</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Duration (minutes)</label>
                        <InputSelect class="form-select" @bind-Value="form.DurationMinutes">
                            <option value="30">30 min</option>
                            <option value="60">60 min</option>
                            <option value="90">90 min</option>
                        </InputSelect>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="form.Reason" />
                        <ValidationMessage For="() => form.Reason" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="form.Notes" />
                    </div>

                    @if (conflictMessage != null)
                    {
                        <div class="alert alert-warning py-1">@conflictMessage</div>
                    }

                    <div class="d-flex gap-2">
                        <button type="submit" class="btn btn-success">@(editingAppointment == null ? "Schedule" : "Update")</button>
                        @if (editingAppointment != null)
                        {
                            <button type="button" class="btn btn-secondary" @onclick="CancelEdit">Cancel</button>
                        }
                    </div>
                </EditForm>
            </div>
        </div>

        <div class="card mt-3">
            <div class="card-header"><strong>Availability — @form.Date.ToShortDateString()</strong></div>
            <div class="card-body p-2">
                @foreach (var hour in Enumerable.Range(8, 10))
                {
                    var isBooked = IsSlotBooked(form.Date, hour);
                    <div class="d-flex justify-content-between align-items-center border-bottom py-1 px-2">
                        <span>@($"{hour:D2}:00")</span>
                        <span class="badge @(isBooked ? "bg-danger" : "bg-success")">@(isBooked ? "Booked" : "Available")</span>
                    </div>
                }
            </div>
        </div>
    </div>

    <div class="col-md-8">
        <div class="mb-3 d-flex gap-2">
            <select class="form-select w-auto" @bind="filterStatus">
                <option value="">All</option>
                <option value="Scheduled">Scheduled</option>
                <option value="Completed">Completed</option>
                <option value="Cancelled">Cancelled</option>
            </select>
            <input type="date" class="form-control w-auto" @bind="filterDate" />
            <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear</button>
        </div>

        <table class="table table-hover">
            <thead>
                <tr>
                    <th>Date/Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Status</th><th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var apt in FilteredAppointments)
                {
                    <tr class="@(apt.Status == AppointmentStatus.Cancelled ? "table-secondary" : "")">
                        <td>@apt.StartTime.ToString("MMM dd, HH:mm") - @apt.EndTime.ToString("HH:mm")</td>
                        <td>@apt.Pet.Name</td>
                        <td>@apt.Pet.Owner.FullName</td>
                        <td>@apt.Reason</td>
                        <td>
                            <span class="badge @StatusBadge(apt.Status)">@apt.Status</span>
                        </td>
                        <td>
                            @if (apt.Status == AppointmentStatus.Scheduled)
                            {
                                <button class="btn btn-sm btn-outline-primary" @onclick="() => Reschedule(apt)">Reschedule</button>
                                <button class="btn btn-sm btn-outline-success" @onclick="() => Complete(apt)">Complete</button>
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(apt)">Cancel</button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
</div>

@code {
    private List<Pet> pets = new();
    private List<Appointment> appointments = new();
    private Appointment? editingAppointment;
    private string? conflictMessage;
    private string filterStatus = "";
    private DateTime? filterDate;

    private AppointmentFormModel form = new();

    private IEnumerable<Appointment> FilteredAppointments
    {
        get
        {
            var q = appointments.AsEnumerable();
            if (!string.IsNullOrEmpty(filterStatus) && Enum.TryParse<AppointmentStatus>(filterStatus, out var s))
                q = q.Where(a => a.Status == s);
            if (filterDate.HasValue)
                q = q.Where(a => a.StartTime.Date == filterDate.Value.Date);
            return q.OrderByDescending(a => a.StartTime);
        }
    }

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).ToListAsync();
        appointments = await db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).ToListAsync();
    }

    private bool IsSlotBooked(DateTime date, int hour)
    {
        var slotStart = date.Date.AddHours(hour);
        var slotEnd = slotStart.AddHours(1);
        return appointments.Any(a => a.Status == AppointmentStatus.Scheduled &&
            a.StartTime < slotEnd && a.EndTime > slotStart &&
            (editingAppointment == null || a.Id != editingAppointment.Id));
    }

    private async Task SaveAppointment()
    {
        if (form.PetId == 0) return;

        var start = form.Date.Date.AddHours(form.StartHour);
        var end = start.AddMinutes(form.DurationMinutes);

        using var db = await DbFactory.CreateDbContextAsync();
        var conflict = await db.Appointments.AnyAsync(a =>
            a.Status == AppointmentStatus.Scheduled &&
            a.StartTime < end && a.EndTime > start &&
            (editingAppointment == null || a.Id != editingAppointment.Id));

        if (conflict)
        {
            conflictMessage = "Time slot conflicts with an existing appointment!";
            return;
        }
        conflictMessage = null;

        if (editingAppointment != null)
        {
            var apt = await db.Appointments.FindAsync(editingAppointment.Id);
            if (apt != null)
            {
                apt.PetId = form.PetId;
                apt.StartTime = start;
                apt.EndTime = end;
                apt.Reason = form.Reason;
                apt.Notes = form.Notes;
            }
            editingAppointment = null;
        }
        else
        {
            db.Appointments.Add(new Appointment
            {
                PetId = form.PetId,
                StartTime = start,
                EndTime = end,
                Reason = form.Reason,
                Notes = form.Notes
            });
        }

        await db.SaveChangesAsync();
        form = new();
        await LoadData();
    }

    private void Reschedule(Appointment apt)
    {
        editingAppointment = apt;
        form = new AppointmentFormModel
        {
            PetId = apt.PetId,
            Date = apt.StartTime.Date,
            StartHour = apt.StartTime.Hour,
            DurationMinutes = (int)(apt.EndTime - apt.StartTime).TotalMinutes,
            Reason = apt.Reason,
            Notes = apt.Notes
        };
    }

    private async Task Complete(Appointment apt)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var a = await db.Appointments.FindAsync(apt.Id);
        if (a != null) { a.Status = AppointmentStatus.Completed; await db.SaveChangesAsync(); }
        await LoadData();
    }

    private async Task Cancel(Appointment apt)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var a = await db.Appointments.FindAsync(apt.Id);
        if (a != null) { a.Status = AppointmentStatus.Cancelled; await db.SaveChangesAsync(); }
        await LoadData();
    }

    private void CancelEdit() { editingAppointment = null; form = new(); conflictMessage = null; }
    private void ClearFilters() { filterStatus = ""; filterDate = null; }

    private string StatusBadge(AppointmentStatus s) => s switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-light"
    };

    private class AppointmentFormModel
    {
        public int PetId { get; set; }
        public DateTime Date { get; set; } = DateTime.Today;
        public int StartHour { get; set; } = 9;
        public int DurationMinutes { get; set; } = 30;
        [Required] public string Reason { get; set; } = "";
        public string? Notes { get; set; }
    }
}

@page "/billing"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Billing</PageTitle>

<h1>💳 Billing & Payments</h1>

<div class="row mt-3">
    <div class="col-md-5">
        <div class="card">
            <div class="card-header"><strong>Create Invoice</strong></div>
            <div class="card-body">
                <EditForm Model="invoiceForm" OnValidSubmit="CreateInvoice" FormName="invoiceForm">
                    <div class="mb-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-select" @bind-Value="invoiceForm.OwnerId">
                            <option value="0">-- Select Owner --</option>
                            @foreach (var o in owners)
                            {
                                <option value="@o.Id">@o.FullName</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Description</label>
                        <InputText class="form-control" @bind-Value="invoiceForm.Description" />
                    </div>

                    <h6>Line Items</h6>
                    @for (int i = 0; i < invoiceForm.Items.Count; i++)
                    {
                        var idx = i;
                        <div class="row mb-1">
                            <div class="col">
                                <input class="form-control form-control-sm" placeholder="Item" @bind="invoiceForm.Items[idx].Description" />
                            </div>
                            <div class="col-3">
                                <input type="number" class="form-control form-control-sm" placeholder="Qty" @bind="invoiceForm.Items[idx].Quantity" />
                            </div>
                            <div class="col-3">
                                <input type="number" step="0.01" class="form-control form-control-sm" placeholder="$" @bind="invoiceForm.Items[idx].Amount" />
                            </div>
                            <div class="col-auto">
                                <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => invoiceForm.Items.RemoveAt(idx)">×</button>
                            </div>
                        </div>
                    }
                    <button type="button" class="btn btn-sm btn-outline-primary mb-2" @onclick="() => invoiceForm.Items.Add(new())">+ Add Item</button>

                    <div class="mb-2">
                        <strong>Total: @invoiceForm.Items.Sum(i => i.Amount * i.Quantity).ToString("C")</strong>
                    </div>
                    <button type="submit" class="btn btn-success">Generate Invoice</button>
                </EditForm>
            </div>
        </div>

        @if (selectedInvoice != null)
        {
            <div class="card mt-3">
                <div class="card-header"><strong>Process Payment — Invoice #@selectedInvoice.Id</strong></div>
                <div class="card-body">
                    <p>Total: @selectedInvoice.TotalAmount.ToString("C") | Paid: @selectedInvoice.Payments.Sum(p => p.Amount).ToString("C") | Remaining: @((selectedInvoice.TotalAmount - selectedInvoice.Payments.Sum(p => p.Amount)).ToString("C"))</p>
                    <EditForm Model="paymentForm" OnValidSubmit="ProcessPayment" FormName="paymentForm">
                        <div class="mb-2">
                            <label class="form-label">Amount</label>
                            <InputNumber class="form-control" @bind-Value="paymentForm.Amount" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Method</label>
                            <InputSelect class="form-select" @bind-Value="paymentForm.Method">
                                @foreach (var m in Enum.GetValues<PaymentMethod>())
                                {
                                    <option value="@m">@m</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Reference</label>
                            <InputText class="form-control" @bind-Value="paymentForm.Reference" />
                        </div>
                        <button type="submit" class="btn btn-primary">Record Payment</button>
                    </EditForm>
                </div>
            </div>
        }
    </div>

    <div class="col-md-7">
        <div class="mb-3 d-flex gap-2">
            <select class="form-select w-auto" @bind="filterStatus">
                <option value="">All Invoices</option>
                <option value="Pending">Pending</option>
                <option value="Paid">Paid</option>
                <option value="Cancelled">Cancelled</option>
            </select>
        </div>

        <table class="table table-hover">
            <thead>
                <tr><th>#</th><th>Owner</th><th>Date</th><th>Total</th><th>Paid</th><th>Status</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var inv in FilteredInvoices)
                {
                    var paid = inv.Payments.Sum(p => p.Amount);
                    <tr class="@(selectedInvoice?.Id == inv.Id ? "table-active" : "")">
                        <td>@inv.Id</td>
                        <td>@inv.Owner.FullName</td>
                        <td>@inv.CreatedDate.ToShortDateString()</td>
                        <td>@inv.TotalAmount.ToString("C")</td>
                        <td>@paid.ToString("C")</td>
                        <td><span class="badge @InvoiceBadge(inv.Status)">@inv.Status</span></td>
                        <td>
                            @if (inv.Status == InvoiceStatus.Pending)
                            {
                                <button class="btn btn-sm btn-outline-primary" @onclick="() => SelectInvoice(inv)">Pay</button>
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelInvoice(inv)">Cancel</button>
                            }
                            <button class="btn btn-sm btn-outline-info" @onclick="() => ViewDetails(inv)">Details</button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>

        @if (detailInvoice != null)
        {
            <div class="card">
                <div class="card-header d-flex justify-content-between">
                    <strong>Invoice #@detailInvoice.Id Details</strong>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => detailInvoice = null">Close</button>
                </div>
                <div class="card-body">
                    <h6>Items</h6>
                    <table class="table table-sm">
                        <thead><tr><th>Description</th><th>Qty</th><th>Price</th><th>Total</th></tr></thead>
                        <tbody>
                            @foreach (var item in detailInvoice.Items)
                            {
                                <tr><td>@item.Description</td><td>@item.Quantity</td><td>@item.Amount.ToString("C")</td><td>@item.LineTotal.ToString("C")</td></tr>
                            }
                        </tbody>
                    </table>
                    <h6>Payment History</h6>
                    <table class="table table-sm">
                        <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th></tr></thead>
                        <tbody>
                            @foreach (var pay in detailInvoice.Payments.OrderByDescending(p => p.PaymentDate))
                            {
                                <tr><td>@pay.PaymentDate.ToShortDateString()</td><td>@pay.Amount.ToString("C")</td><td>@pay.Method</td><td>@pay.Reference</td></tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        }
    </div>
</div>

@code {
    private List<Owner> owners = new();
    private List<Invoice> invoices = new();
    private Invoice? selectedInvoice;
    private Invoice? detailInvoice;
    private string filterStatus = "";

    private InvoiceFormModel invoiceForm = new();
    private PaymentFormModel paymentForm = new();

    private IEnumerable<Invoice> FilteredInvoices
    {
        get
        {
            var q = invoices.AsEnumerable();
            if (!string.IsNullOrEmpty(filterStatus) && Enum.TryParse<InvoiceStatus>(filterStatus, out var s))
                q = q.Where(i => i.Status == s);
            return q.OrderByDescending(i => i.CreatedDate);
        }
    }

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        owners = await db.Owners.ToListAsync();
        invoices = await db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .ToListAsync();
    }

    private async Task CreateInvoice()
    {
        if (invoiceForm.OwnerId == 0 || invoiceForm.Items.Count == 0) return;
        using var db = await DbFactory.CreateDbContextAsync();
        var invoice = new Invoice
        {
            OwnerId = invoiceForm.OwnerId,
            Description = invoiceForm.Description,
            CreatedDate = DateTime.Now,
            TotalAmount = invoiceForm.Items.Sum(i => i.Amount * i.Quantity),
            Items = invoiceForm.Items.Select(i => new InvoiceItem
            {
                Description = i.Description,
                Amount = i.Amount,
                Quantity = i.Quantity
            }).ToList()
        };
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        invoiceForm = new();
        await LoadData();
    }

    private void SelectInvoice(Invoice inv)
    {
        selectedInvoice = inv;
        paymentForm = new PaymentFormModel { Amount = inv.TotalAmount - inv.Payments.Sum(p => p.Amount) };
    }

    private void ViewDetails(Invoice inv) => detailInvoice = inv;

    private async Task ProcessPayment()
    {
        if (selectedInvoice == null) return;
        using var db = await DbFactory.CreateDbContextAsync();
        db.Payments.Add(new Payment
        {
            InvoiceId = selectedInvoice.Id,
            Amount = paymentForm.Amount,
            Method = paymentForm.Method,
            Reference = paymentForm.Reference,
            PaymentDate = DateTime.Now
        });

        var totalPaid = selectedInvoice.Payments.Sum(p => p.Amount) + paymentForm.Amount;
        if (totalPaid >= selectedInvoice.TotalAmount)
        {
            var inv = await db.Invoices.FindAsync(selectedInvoice.Id);
            if (inv != null) inv.Status = InvoiceStatus.Paid;
        }

        await db.SaveChangesAsync();
        selectedInvoice = null;
        paymentForm = new();
        await LoadData();
    }

    private async Task CancelInvoice(Invoice inv)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var i = await db.Invoices.FindAsync(inv.Id);
        if (i != null) { i.Status = InvoiceStatus.Cancelled; await db.SaveChangesAsync(); }
        await LoadData();
    }

    private string InvoiceBadge(InvoiceStatus s) => s switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Cancelled => "bg-secondary",
        _ => "bg-light"
    };

    private class InvoiceFormModel
    {
        public int OwnerId { get; set; }
        public string? Description { get; set; }
        public List<ItemModel> Items { get; set; } = new() { new() };
    }

    private class ItemModel
    {
        public string Description { get; set; } = "";
        public int Quantity { get; set; } = 1;
        public decimal Amount { get; set; }
    }

    private class PaymentFormModel
    {
        public decimal Amount { get; set; }
        public PaymentMethod Method { get; set; }
        public string? Reference { get; set; }
    }
}

