    }

    private async Task SaveOwner()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        if (editingOwner != null)
        {
            var owner = await db.Owners.FindAsync(editingOwner.Id);
            if (owner != null)
            {
                owner.FirstName = ownerForm.FirstName;
                owner.LastName = ownerForm.LastName;
                owner.Phone = ownerForm.Phone;
                owner.Email = ownerForm.Email;
                await db.SaveChangesAsync();
            }
            editingOwner = null;
        }
        else
        {
            var owner = new Owner
            {
                FirstName = ownerForm.FirstName,
                LastName = ownerForm.LastName,
                Phone = ownerForm.Phone,
                Email = ownerForm.Email
            };
            db.Owners.Add(owner);
            await db.SaveChangesAsync();
        }
        ownerForm = new();
        await LoadData();
    }

    private async Task SavePet()
    {
        if (petForm.OwnerId == 0) return;
        using var db = await DbFactory.CreateDbContextAsync();
        var pet = new Pet
        {
            Name = petForm.Name,
            Species = petForm.Species,
            Breed = petForm.Breed,
            WeightKg = petForm.WeightKg,
            OwnerId = petForm.OwnerId
        };
        db.Pets.Add(pet);
        await db.SaveChangesAsync();
        petForm = new();
        await LoadData();
    }

    private void EditOwner(Owner owner)
    {
        editingOwner = owner;
        ownerForm = new OwnerFormModel
        {
            FirstName = owner.FirstName,
            LastName = owner.LastName,
            Phone = owner.Phone,
            Email = owner.Email
        };
