@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Billing</PageTitle>

<h1>💳 Billing & Payments</h1>

<div class="row mt-3">
    <div class="col-md-5">
        <div class="card">
            <div class="card-header"><strong>Create Invoice</strong></div>
            <div class="card-body">
                <EditForm Model="invoiceForm" OnValidSubmit="CreateInvoice" FormName="invoiceForm">
                    <div class="mb-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-select" @bind-Value="invoiceForm.OwnerId">
                            <option value="0">-- Select Owner --</option>
                            @foreach (var o in owners)
                            {
                                <option value="@o.Id">@o.FullName</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Description</label>
                        <InputText class="form-control" @bind-Value="invoiceForm.Description" />
                    </div>

                    <h6>Line Items</h6>
                    @for (int i = 0; i < invoiceForm.Items.Count; i++)
                    {
                        var idx = i;
                        <div class="row mb-1">
                            <div class="col">
                                <input class="form-control form-control-sm" placeholder="Item" @bind="invoiceForm.Items[idx].Description" />
                            </div>
                            <div class="col-3">
                                <input type="number" class="form-control form-control-sm" placeholder="Qty" @bind="invoiceForm.Items[idx].Quantity" />
                            </div>
                            <div class="col-3">
                                <input type="number" step="0.01" class="form-control form-control-sm" placeholder="$" @bind="invoiceForm.Items[idx].Amount" />
                            </div>
                            <div class="col-auto">
                                <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => invoiceForm.Items.RemoveAt(idx)">×</button>
                            </div>
                        </div>
                    }
                    <button type="button" class="btn btn-sm btn-outline-primary mb-2" @onclick="() => invoiceForm.Items.Add(new())">+ Add Item</button>

                    <div class="mb-2">
                        <strong>Total: @invoiceForm.Items.Sum(i => i.Amount * i.Quantity).ToString("C")</strong>
                    </div>
                    <button type="submit" class="btn btn-success">Generate Invoice</button>
                </EditForm>
            </div>
        </div>

        @if (selectedInvoice != null)
        {
            <div class="card mt-3">
                <div class="card-header"><strong>Process Payment — Invoice #@selectedInvoice.Id</strong></div>
                <div class="card-body">
                    <p>Total: @selectedInvoice.TotalAmount.ToString("C") | Paid: @selectedInvoice.Payments.Sum(p => p.Amount).ToString("C") | Remaining: @((selectedInvoice.TotalAmount - selectedInvoice.Payments.Sum(p => p.Amount)).ToString("C"))</p>
                    <EditForm Model="paymentForm" OnValidSubmit="ProcessPayment" FormName="paymentForm">
                        <div class="mb-2">
                            <label class="form-label">Amount</label>
                            <InputNumber class="form-control" @bind-Value="paymentForm.Amount" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Method</label>
                            <InputSelect class="form-select" @bind-Value="paymentForm.Method">
                                @foreach (var m in Enum.GetValues<PaymentMethod>())
                                {
                                    <option value="@m">@m</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Reference</label>
                            <InputText class="form-control" @bind-Value="paymentForm.Reference" />
                        </div>
                        <button type="submit" class="btn btn-primary">Record Payment</button>
                    </EditForm>
                </div>
            </div>
        }
    </div>

    <div class="col-md-7">
        <div class="mb-3 d-flex gap-2">
            <select class="form-select w-auto" @bind="filterStatus">
                <option value="">All Invoices</option>
                <option value="Pending">Pending</option>
                <option value="Paid">Paid</option>
                <option value="Cancelled">Cancelled</option>
            </select>
        </div>

        <table class="table table-hover">
            <thead>
                <tr><th>#</th><th>Owner</th><th>Date</th><th>Total</th><th>Paid</th><th>Status</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var inv in FilteredInvoices)
                {
                    var paid = inv.Payments.Sum(p => p.Amount);
                    <tr class="@(selectedInvoice?.Id == inv.Id ? "table-active" : "")">
                        <td>@inv.Id</td>
                        <td>@inv.Owner.FullName</td>
                        <td>@inv.CreatedDate.ToShortDateString()</td>
                        <td>@inv.TotalAmount.ToString("C")</td>
                        <td>@paid.ToString("C")</td>
                        <td><span class="badge @InvoiceBadge(inv.Status)">@inv.Status</span></td>
                        <td>
                            @if (inv.Status == InvoiceStatus.Pending)
                            {
                                <button class="btn btn-sm btn-outline-primary" @onclick="() => SelectInvoice(inv)">Pay</button>
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelInvoice(inv)">Cancel</button>
                            }
                            <button class="btn btn-sm btn-outline-info" @onclick="() => ViewDetails(inv)">Details</button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>

        @if (detailInvoice != null)
        {
            <div class="card">
                <div class="card-header d-flex justify-content-between">
                    <strong>Invoice #@detailInvoice.Id Details</strong>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => detailInvoice = null">Close</button>
                </div>
                <div class="card-body">
                    <h6>Items</h6>
                    <table class="table table-sm">
                        <thead><tr><th>Description</th><th>Qty</th><th>Price</th><th>Total</th></tr></thead>
                        <tbody>
                            @foreach (var item in detailInvoice.Items)
                            {
                                <tr><td>@item.Description</td><td>@item.Quantity</td><td>@item.Amount.ToString("C")</td><td>@item.LineTotal.ToString("C")</td></tr>
                            }
                        </tbody>
                    </table>
                    <h6>Payment History</h6>
                    <table class="table table-sm">
                        <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th></tr></thead>
                        <tbody>
                            @foreach (var pay in detailInvoice.Payments.OrderByDescending(p => p.PaymentDate))
                            {
                                <tr><td>@pay.PaymentDate.ToShortDateString()</td><td>@pay.Amount.ToString("C")</td><td>@pay.Method</td><td>@pay.Reference</td></tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        }
    </div>
</div>

@code {
    private List<Owner> owners = new();
    private List<Invoice> invoices = new();
    private Invoice? selectedInvoice;
    private Invoice? detailInvoice;
    private string filterStatus = "";

    private InvoiceFormModel invoiceForm = new();
    private PaymentFormModel paymentForm = new();

    private IEnumerable<Invoice> FilteredInvoices
    {
        get
        {
            var q = invoices.AsEnumerable();
            if (!string.IsNullOrEmpty(filterStatus) && Enum.TryParse<InvoiceStatus>(filterStatus, out var s))
                q = q.Where(i => i.Status == s);
            return q.OrderByDescending(i => i.CreatedDate);
        }
    }

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        owners = await db.Owners.ToListAsync();
        invoices = await db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .ToListAsync();
    }

    private async Task CreateInvoice()
    {
        if (invoiceForm.OwnerId == 0 || invoiceForm.Items.Count == 0) return;
        using var db = await DbFactory.CreateDbContextAsync();
        var invoice = new Invoice
        {
            OwnerId = invoiceForm.OwnerId,
            Description = invoiceForm.Description,
            CreatedDate = DateTime.Now,
            TotalAmount = invoiceForm.Items.Sum(i => i.Amount * i.Quantity),
            Items = invoiceForm.Items.Select(i => new InvoiceItem
            {
                Description = i.Description,
                Amount = i.Amount,
                Quantity = i.Quantity
            }).ToList()
        };
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        invoiceForm = new();
        await LoadData();
    }

    private void SelectInvoice(Invoice inv)
    {
        selectedInvoice = inv;
        paymentForm = new PaymentFormModel { Amount = inv.TotalAmount - inv.Payments.Sum(p => p.Amount) };
    }

    private void ViewDetails(Invoice inv) => detailInvoice = inv;

    private async Task ProcessPayment()
    {
        if (selectedInvoice == null) return;
        using var db = await DbFactory.CreateDbContextAsync();
        db.Payments.Add(new Payment
        {
            InvoiceId = selectedInvoice.Id,
            Amount = paymentForm.Amount,
            Method = paymentForm.Method,
            Reference = paymentForm.Reference,
            PaymentDate = DateTime.Now
        });

        var totalPaid = selectedInvoice.Payments.Sum(p => p.Amount) + paymentForm.Amount;
        if (totalPaid >= selectedInvoice.TotalAmount)
        {
            var inv = await db.Invoices.FindAsync(selectedInvoice.Id);
            if (inv != null) inv.Status = InvoiceStatus.Paid;
        }

        await db.SaveChangesAsync();
        selectedInvoice = null;
        paymentForm = new();
        await LoadData();
    }

    private async Task CancelInvoice(Invoice inv)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var i = await db.Invoices.FindAsync(inv.Id);
        if (i != null) { i.Status = InvoiceStatus.Cancelled; await db.SaveChangesAsync(); }
        await LoadData();
    }

    private string InvoiceBadge(InvoiceStatus s) => s switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Cancelled => "bg-secondary",
        _ => "bg-light"
    };

    private class InvoiceFormModel
    {
        public int OwnerId { get; set; }
        public string? Description { get; set; }
        public List<ItemModel> Items { get; set; } = new() { new() };
    }

    private class ItemModel
    {
        public string Description { get; set; } = "";
        public int Quantity { get; set; } = 1;
        public decimal Amount { get; set; }
    }

    private class PaymentFormModel
    {
        public decimal Amount { get; set; }
        public PaymentMethod Method { get; set; }
        public string? Reference { get; set; }
    }
}
