+@page "/appointments"
+@rendermode InteractiveServer
+@using Microsoft.EntityFrameworkCore
+@using VetClinic.Data
+@using VetClinic.Data.Models
+@inject IDbContextFactory<ApplicationDbContext> DbFactory
+
+<PageTitle>Appointments</PageTitle>
+
+<h1>📅 Appointment Scheduling</h1>
+
+<div class="row mt-3">
+    <div class="col-md-4">
+        <div class="card">
+            <div class="card-header">
+                <strong>@(editingAppointment == null ? "New Appointment" : "Edit Appointment")</strong>
+            </div>
+            <div class="card-body">
+                <EditForm Model="form" OnValidSubmit="SaveAppointment" FormName="appointmentForm">
+                    <DataAnnotationsValidator />
+                    <div class="mb-2">
+                        <label class="form-label">Pet</label>
+                        <InputSelect class="form-select" @bind-Value="form.PetId">
+                            <option value="0">-- Select Pet --</option>
+                            @foreach (var pet in pets)
+                            {
+                                <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
+                            }
+                        </InputSelect>
+                    </div>
+                    <div class="mb-2">
+                        <label class="form-label">Date</label>
+                        <InputDate class="form-control" @bind-Value="form.Date" />
+                    </div>
+                    <div class="mb-2">
+                        <label class="form-label">Start Time</label>
+                        <InputSelect class="form-select" @bind-Value="form.StartHour">
+                            @foreach (var hour in Enumerable.Range(8, 10))
+                            {
+                                <option value="@hour">@($"{hour:D2}:00")</option>
+                            }
+                        </InputSelect>
+                    </div>
+                    <div class="mb-2">
+                        <label class="form-label">Duration (minutes)</label>
+                        <InputSelect class="form-select" @bind-Value="form.DurationMinutes">
+                            <option value="30">30 min</option>
+                            <option value="60">60 min</option>
+                            <option value="90">90 min</option>
+                        </InputSelect>
+                    </div>
+                    <div class="mb-2">
+                        <label class="form-label">Reason</label>
+                        <InputText class="form-control" @bind-Value="form.Reason" />
+                        <ValidationMessage For="() => form.Reason" />
+                    </div>
+                    <div class="mb-2">
+                        <label class="form-label">Notes</label>
+                        <InputTextArea class="form-control" @bind-Value="form.Notes" />
+                    </div>
+
+                    @if (conflictMessage != null)
+                    {
+                        <div class="alert alert-warning py-1">@conflictMessage</div>
+                    }
+
+                    <div class="d-flex gap-2">
+                        <button type="submit" class="btn btn-success">@(editingAppointment == null ? "Schedule" : "Update")</button>
+                        @if (editingAppointment != null)
+                        {
+                            <button type="button" class="btn btn-secondary" @onclick="CancelEdit">Cancel</button>
+                        }
+                    </div>
+                </EditForm>
+            </div>
+        </div>
+
+        <div class="card mt-3">
+            <div class="card-header"><strong>Availability — @form.Date.ToShortDateString()</strong></div>
+            <div class="card-body p-2">
+                @foreach (var hour in Enumerable.Range(8, 10))
+                {
+                    var isBooked = IsSlotBooked(form.Date, hour);
+                    <div class="d-flex justify-content-between align-items-center border-bottom py-1 px-2">
+                        <span>@($"{hour:D2}:00")</span>
+                        <span class="badge @(isBooked ? "bg-danger" : "bg-success")">@(isBooked ? "Booked" : "Available")</span>
+                    </div>
+                }
+            </div>
+        </div>
+    </div>
+
+    <div class="col-md-8">
+        <div class="mb-3 d-flex gap-2">
+            <select class="form-select w-auto" @bind="filterStatus">
+                <option value="">All</option>
+                <option value="Scheduled">Scheduled</option>
+                <option value="Completed">Completed</option>
+                <option value="Cancelled">Cancelled</option>
+            </select>
+            <input type="date" class="form-control w-auto" @bind="filterDate" />
+            <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear</button>
+        </div>
+
+        <table class="table table-hover">
+            <thead>
+                <tr>
+                    <th>Date/Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Status</th><th>Actions</th>
+                </tr>
+            </thead>
+            <tbody>
+                @foreach (var apt in FilteredAppointments)
+                {
+                    <tr class="@(apt.Status == AppointmentStatus.Cancelled ? "table-secondary" : "")">
+                        <td>@apt.StartTime.ToString("MMM dd, HH:mm") - @apt.EndTime.ToString("HH:mm")</td>
+                        <td>@apt.Pet.Name</td>
+                        <td>@apt.Pet.Owner.FullName</td>
+                        <td>@apt.Reason</td>
+                        <td>
+                            <span class="badge @StatusBadge(apt.Status)">@apt.Status</span>
+                        </td>
+                        <td>
+                            @if (apt.Status == AppointmentStatus.Scheduled)
+                            {
+                                <button class="btn btn-sm btn-outline-primary" @onclick="() => Reschedule(apt)">Reschedule</button>
+                                <button class="btn btn-sm btn-outline-success" @onclick="() => Complete(apt)">Complete</button>
+                                <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(apt)">Cancel</button>
+                            }
+                        </td>
+                    </tr>
+                }
+            </tbody>
+        </table>
+    </div>
+</div>
+
+@code {
+    private List<Pet> pets = new();
+    private List<Appointment> appointments = new();
+    private Appointment? editingAppointment;
+    private string? conflictMessage;
+    private string filterStatus = "";
+    private DateTime? filterDate;
+
+    private AppointmentFormModel form = new();
+
+    private IEnumerable<Appointment> FilteredAppointments
+    {
+        get
+        {
+            var q = appointments.AsEnumerable();
+            if (!string.IsNullOrEmpty(filterStatus) && Enum.TryParse<AppointmentStatus>(filterStatus, out var s))
+                q = q.Where(a => a.Status == s);
+            if (filterDate.HasValue)
+                q = q.Where(a => a.StartTime.Date == filterDate.Value.Date);
+            return q.OrderByDescending(a => a.StartTime);
+        }
+    }
+
+    protected override async Task OnInitializedAsync() => await LoadData();
+
+    private async Task LoadData()
+    {
+        using var db = await DbFactory.CreateDbContextAsync();
+        pets = await db.Pets.Include(p => p.Owner).ToListAsync();
+        appointments = await db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).ToListAsync();
+    }
+
+    private bool IsSlotBooked(DateTime date, int hour)
+    {
+        var slotStart = date.Date.AddHours(hour);
+        var slotEnd = slotStart.AddHours(1);
+        return appointments.Any(a => a.Status == AppointmentStatus.Scheduled &&
+            a.StartTime < slotEnd && a.EndTime > slotStart &&
+            (editingAppointment == null || a.Id != editingAppointment.Id));
+    }
+
+    private async Task SaveAppointment()
+    {
+        if (form.PetId == 0) return;
+
+        var start = form.Date.Date.AddHours(form.StartHour);
+        var end = start.AddMinutes(form.DurationMinutes);
+
+        using var db = await DbFactory.CreateDbContextAsync();
+        var conflict = await db.Appointments.AnyAsync(a =>
+            a.Status == AppointmentStatus.Scheduled &&
+            a.StartTime < end && a.EndTime > start &&
+            (editingAppointment == null || a.Id != editingAppointment.Id));
+
+        if (conflict)
+        {
+            conflictMessage = "Time slot conflicts with an existing appointment!";
+            return;
+        }
+        conflictMessage = null;
+
+        if (editingAppointment != null)
+        {
+            var apt = await db.Appointments.FindAsync(editingAppointment.Id);
+            if (apt != null)
+            {
+                apt.PetId = form.PetId;
+                apt.StartTime = start;
+                apt.EndTime = end;
+                apt.Reason = form.Reason;
+                apt.Notes = form.Notes;
+            }
+            editingAppointment = null;
+        }
+        else
+        {
+            db.Appointments.Add(new Appointment
+            {
+                PetId = form.PetId,
+                StartTime = start,
+                EndTime = end,
+                Reason = form.Reason,
+                Notes = form.Notes
+            });
+        }
+
+        await db.SaveChangesAsync();
+        form = new();
+        await LoadData();
+    }
+
+    private void Reschedule(Appointment apt)
+    {
+        editingAppointment = apt;
+        form = new AppointmentFormModel
+        {
+            PetId = apt.PetId,
+            Date = apt.StartTime.Date,
+            StartHour = apt.StartTime.Hour,
+            DurationMinutes = (int)(apt.EndTime - apt.StartTime).TotalMinutes,
+            Reason = apt.Reason,
+            Notes = apt.Notes
+        };
+    }
+
+    private async Task Complete(Appointment apt)
+    {
+        using var db = await DbFactory.CreateDbContextAsync();
+        var a = await db.Appointments.FindAsync(apt.Id);
+        if (a != null) { a.Status = AppointmentStatus.Completed; await db.SaveChangesAsync(); }
+        await LoadData();
+    }
+
+    private async Task Cancel(Appointment apt)
+    {
+        using var db = await DbFactory.CreateDbContextAsync();
+        var a = await db.Appointments.FindAsync(apt.Id);
+        if (a != null) { a.Status = AppointmentStatus.Cancelled; await db.SaveChangesAsync(); }
+        await LoadData();
+    }
+
+    private void CancelEdit() { editingAppointment = null; form = new(); conflictMessage = null; }
+    private void ClearFilters() { filterStatus = ""; filterDate = null; }
+
+    private string StatusBadge(AppointmentStatus s) => s switch
+    {
+        AppointmentStatus.Scheduled => "bg-primary",
+        AppointmentStatus.Completed => "bg-success",
+        AppointmentStatus.Cancelled => "bg-secondary",
+        _ => "bg-light"
+    };
+
+    private class AppointmentFormModel
+    {
+        public int PetId { get; set; }
+        public DateTime Date { get; set; } = DateTime.Today;
+        public int StartHour { get; set; } = 9;
+        public int DurationMinutes { get; set; } = 30;
+        [Required] public string Reason { get; set; } = "";
+        public string? Notes { get; set; }
+    }
+}
+

