@page "/patients"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Patients</PageTitle>

<h1>🐕 Patient Records</h1>

<div class="row mt-3">
    <div class="col-md-5">
        <div class="card">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>@(editingOwner == null ? "Register New Owner & Pet" : "Edit Owner")</strong>
                @if (editingOwner != null)
                {
                    <button class="btn btn-sm btn-outline-secondary" @onclick="ResetForm">Cancel</button>
                }
            </div>
            <div class="card-body">
                <EditForm Model="ownerForm" OnValidSubmit="SaveOwner" FormName="ownerForm">
                    <DataAnnotationsValidator />
                    <div class="mb-2">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="ownerForm.FirstName" />
                        <ValidationMessage For="() => ownerForm.FirstName" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="ownerForm.LastName" />
                        <ValidationMessage For="() => ownerForm.LastName" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="ownerForm.Phone" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="ownerForm.Email" />
                    </div>
                    <button type="submit" class="btn btn-success">@(editingOwner == null ? "Register Owner" : "Update Owner")</button>
                </EditForm>

                @if (editingOwner == null)
                {
                    <hr />
                    <h6>Add Pet</h6>
                    <EditForm Model="petForm" OnValidSubmit="SavePet" FormName="petForm">
                        <DataAnnotationsValidator />
                        <div class="mb-2">
                            <label class="form-label">Owner</label>
                            <InputSelect class="form-select" @bind-Value="petForm.OwnerId">
                                <option value="0">-- Select Owner --</option>
                                @foreach (var o in owners)
                                {
                                    <option value="@o.Id">@o.FullName</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Pet Name</label>
                            <InputText class="form-control" @bind-Value="petForm.Name" />
                            <ValidationMessage For="() => petForm.Name" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Species</label>
                            <InputSelect class="form-select" @bind-Value="petForm.Species">
                                <option value="">-- Select --</option>
                                <option>Dog</option>
                                <option>Cat</option>
                                <option>Bird</option>
                                <option>Rabbit</option>
                                <option>Reptile</option>
                                <option>Other</option>
                            </InputSelect>
                            <ValidationMessage For="() => petForm.Species" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Breed</label>
                            <InputText class="form-control" @bind-Value="petForm.Breed" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Weight (kg)</label>
                            <InputNumber class="form-control" @bind-Value="petForm.WeightKg" />
                        </div>
                        <button type="submit" class="btn btn-primary">Register Pet</button>
                    </EditForm>
                }
            </div>
        </div>
    </div>

    <div class="col-md-7">
        <div class="mb-3">
            <input type="text" class="form-control" placeholder="Search pets or owners..." @bind="searchTerm" @bind:event="oninput" />
        </div>

        @foreach (var owner in FilteredOwners)
        {
            <div class="card mb-2">
                <div class="card-header d-flex justify-content-between">
                    <span><strong>@owner.FullName</strong> — @owner.Phone</span>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => EditOwner(owner)">Edit</button>
                </div>
                <div class="card-body p-2">
                    @foreach (var pet in owner.Pets)
                    {
                        <div class="border rounded p-2 mb-2">
                            <div class="d-flex justify-content-between">
                                <span><strong>@pet.Name</strong> (@pet.Species@(pet.Breed != null ? $" - {pet.Breed}" : "")) @(pet.WeightKg.HasValue ? $"{pet.WeightKg} kg" : "")</span>
                                <button class="btn btn-sm btn-outline-info" @onclick="() => SelectPet(pet)">Medical History</button>
                            </div>
                        </div>
                    }
                </div>
            </div>
        }
    </div>
</div>

@if (selectedPet != null)
{
    <div class="modal fade show d-block" tabindex="-1" style="background:rgba(0,0,0,0.5)">
        <div class="modal-dialog modal-lg">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Medical History — @selectedPet.Name</h5>
                    <button type="button" class="btn-close" @onclick="() => selectedPet = null"></button>
                </div>
                <div class="modal-body">
                    <h6>Add Treatment Note</h6>
                    <EditForm Model="treatmentForm" OnValidSubmit="SaveTreatment" FormName="treatmentForm">
                        <DataAnnotationsValidator />
                        <div class="row mb-2">
                            <div class="col">
                                <InputText class="form-control" placeholder="Description" @bind-Value="treatmentForm.Description" />
                                <ValidationMessage For="() => treatmentForm.Description" />
                            </div>
                            <div class="col-auto">
                                <InputNumber class="form-control" placeholder="Cost" @bind-Value="treatmentForm.Cost" />
                            </div>
                        </div>
                        <div class="mb-2">
                            <InputTextArea class="form-control" placeholder="Notes..." @bind-Value="treatmentForm.Notes" />
                        </div>
                        <div class="row mb-2">
                            <div class="col">
                                <InputText class="form-control" placeholder="Performed by" @bind-Value="treatmentForm.PerformedBy" />
                            </div>
                            <div class="col-auto">
                                <button type="submit" class="btn btn-success">Add Treatment</button>
                            </div>
                        </div>
                    </EditForm>
                    <hr />
                    <table class="table table-sm">
                        <thead>
                            <tr><th>Date</th><th>Description</th><th>Notes</th><th>By</th><th>Cost</th></tr>
                        </thead>
                        <tbody>
                            @foreach (var t in selectedPet.Treatments.OrderByDescending(t => t.Date))
                            {
                                <tr>
                                    <td>@t.Date.ToShortDateString()</td>
                                    <td>@t.Description</td>
                                    <td>@t.Notes</td>
                                    <td>@t.PerformedBy</td>
                                    <td>@t.Cost.ToString("C")</td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private List<Owner> owners = new();
    private string searchTerm = "";
    private Owner? editingOwner;
    private Pet? selectedPet;

    private OwnerFormModel ownerForm = new();
    private PetFormModel petForm = new();
    private TreatmentFormModel treatmentForm = new();

    private IEnumerable<Owner> FilteredOwners => string.IsNullOrWhiteSpace(searchTerm)
        ? owners
        : owners.Where(o =>
            o.FullName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            o.Pets.Any(p => p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)));

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        owners = await db.Owners.Include(o => o.Pets).ThenInclude(p => p.Treatments).ToListAsync();
    }

    private async Task SaveOwner()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        if (editingOwner != null)
        {
            var owner = await db.Owners.FindAsync(editingOwner.Id);
            if (owner != null)
            {
                owner.FirstName = ownerForm.FirstName;
                owner.LastName = ownerForm.LastName;
                owner.Phone = ownerForm.Phone;
                owner.Email = ownerForm.Email;
                await db.SaveChangesAsync();
            }
            editingOwner = null;
        }
        else
        {
            var owner = new Owner
            {
                FirstName = ownerForm.FirstName,
                LastName = ownerForm.LastName,
                Phone = ownerForm.Phone,
                Email = ownerForm.Email
            };
            db.Owners.Add(owner);
            await db.SaveChangesAsync();
        }
        ownerForm = new();
        await LoadData();
    }

    private async Task SavePet()
    {
        if (petForm.OwnerId == 0) return;
        using var db = await DbFactory.CreateDbContextAsync();
        var pet = new Pet
        {
            Name = petForm.Name,
            Species = petForm.Species,
            Breed = petForm.Breed,
            WeightKg = petForm.WeightKg,
            OwnerId = petForm.OwnerId
        };
        db.Pets.Add(pet);
        await db.SaveChangesAsync();
        petForm = new();
        await LoadData();
    }

    private void EditOwner(Owner owner)
    {
        editingOwner = owner;
        ownerForm = new OwnerFormModel
        {
            FirstName = owner.FirstName,
            LastName = owner.LastName,
            Phone = owner.Phone,
            Email = owner.Email
        };
    }

    private void ResetForm()
    {
        editingOwner = null;
        ownerForm = new();
    }

    private void SelectPet(Pet pet)
    {
        selectedPet = pet;
        treatmentForm = new();
    }

    private async Task SaveTreatment()
    {
        if (selectedPet == null) return;
        using var db = await DbFactory.CreateDbContextAsync();
        var treatment = new Treatment
        {
            PetId = selectedPet.Id,
            Date = DateTime.Now,
            Description = treatmentForm.Description,
            Notes = treatmentForm.Notes,
            PerformedBy = treatmentForm.PerformedBy,
            Cost = treatmentForm.Cost
        };
        db.Treatments.Add(treatment);
        await db.SaveChangesAsync();
        treatmentForm = new();
        await LoadData();
        selectedPet = owners.SelectMany(o => o.Pets).FirstOrDefault(p => p.Id == selectedPet.Id);
    }

    private class OwnerFormModel
    {
        [Required] public string FirstName { get; set; } = "";
        [Required] public string LastName { get; set; } = "";
        public string? Phone { get; set; }
        public string? Email { get; set; }
    }

    private class PetFormModel
    {
        public int OwnerId { get; set; }
        [Required] public string Name { get; set; } = "";
        [Required] public string Species { get; set; } = "";
        public string? Breed { get; set; }
        public double? WeightKg { get; set; }
    }

    private class TreatmentFormModel
    {
        [Required] public string Description { get; set; } = "";
        public string? Notes { get; set; }
        public string? PerformedBy { get; set; }
        public decimal Cost { get; set; }
    }
}

