@page "/billing"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Billing</PageTitle>

<h1>💳 Billing & Payments</h1>

<div class="row mt-3">
    <div class="col-md-5">
        <div class="card">
            <div class="card-header"><strong>Create Invoice</strong></div>
            <div class="card-body">
                <EditForm Model="invoiceForm" OnValidSubmit="CreateInvoice" FormName="invoiceForm">
                    <div class="mb-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-select" @bind-Value="invoiceForm.OwnerId">
                            <option value="0">-- Select Owner --</option>
                            @foreach (var o in owners)
                            {
                                <option value="@o.Id">@o.FullName</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Description</label>
                        <InputText class="form-control" @bind-Value="invoiceForm.Description" />
                    </div>

                    <h6>Line Items</h6>
                    @for (int i = 0; i < invoiceForm.Items.Count; i++)
                    {
                        var idx = i;
                        <div class="row mb-1">
                            <div class="col">
                                <input class="form-control form-control-sm" placeholder="Item" @bind="invoiceForm.Items[idx].Description" />
                            </div>
                            <div class="col-3">
                                <input type="number" class="form-control form-control-sm" placeholder="Qty" @bind="invoiceForm.Items[idx].Quantity" />
                            </div>
                            <div class="col-3">
                                <input type="number" step="0.01" class="form-control form-control-sm" placeholder="$" @bind="invoiceForm.Items[idx].Amount" />
                            </div>
                            <div class="col-auto">
                                <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => invoiceForm.Items.RemoveAt(idx)">×</button>
                            </div>
                        </div>
                    }
                    <button type="button" class="btn btn-sm btn-outline-primary mb-2" @onclick="() => invoiceForm.Items.Add(new())">+ Add Item</button>

                    <div class="mb-2">
                        <strong>Total: @invoiceForm.Items.Sum(i => i.Amount * i.Quantity).ToString("C")</strong>
                    </div>
                    <button type="submit" class="btn btn-success">Generate Invoice</button>
                </EditForm>
            </div>
        </div>

        @if (selectedInvoice != null)
        {
            <div class="card mt-3">
                <div class="card-header"><strong>Process Payment — Invoice #@selectedInvoice.Id</strong></div>
                <div class="card-body">
                    <p>Total: @selectedInvoice.TotalAmount.ToString("C") | Paid: @selectedInvoice.Payments.Sum(p => p.Amount).ToString("C") | Remaining: @((selectedInvoice.TotalAmount - selectedInvoice.Payments.Sum(p => p.Amount)).ToString("C"))</p>
                    <EditForm Model="paymentForm" OnValidSubmit="ProcessPayment" FormName="paymentForm">
                        <div class="mb-2">
                            <label class="form-label">Amount</label>
                            <InputNumber class="form-control" @bind-Value="paymentForm.Amount" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Method</label>
                            <InputSelect class="form-select" @bind-Value="paymentForm.Method">
                                @foreach (var m in Enum.GetValues<PaymentMethod>())
                                {
                                    <option value="@m">@m</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Reference</label>
                            <InputText class="form-control" @bind-Value="paymentForm.Reference" />
                        </div>
                        <button type="submit" class="btn btn-primary">Record Payment</button>
                    </EditForm>
                </div>
            </div>
        }
    </div>

    <div class="col-md-7">
        <div class="mb-3 d-flex gap-2">
            <select class="form-select w-auto" @bind="filterStatus">
                <option value="">All Invoices</option>
                <option value="Pending">Pending</option>
                <option value="Paid">Paid</option>
                <option value="Cancelled">Cancelled</option>
            </select>
        </div>

        <table class="table table-hover">
            <thead>
                <tr><th>#</th><th>Owner</th><th>Date</th><th>Total</th><th>Paid</th><th>Status</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var inv in FilteredInvoices)
                {
                    var paid = inv.Payments.Sum(p => p.Amount);
                    <tr class="@(selectedInvoice?.Id == inv.Id ? "table-active" : "")">
